import React, { useState, useEffect } from 'react';
import './App.css';

const GOOGLE_API_KEY = process.env.REACT_APP_GOOGLE_API_KEY;
const GOOGLE_CSE_ID = process.env.REACT_APP_GOOGLE_CSE_ID;
const HAS_GOOGLE_IMAGE_API = Boolean(GOOGLE_API_KEY && GOOGLE_CSE_ID);

/**
 * Parses characters.txt into an array of columns.
 * Each block separated by a blank line becomes one column.
 * The first non-empty line is the column name; the rest are entries.
 */
function parseCharactersTxt(text) {
  const blocks = text.trim().split(/\n[ \t]*\n/);
  return blocks
    .map(block => {
      const lines = block.split('\n').map(l => l.trim()).filter(Boolean);
      if (lines.length < 1) return null;
      const [name, ...entries] = lines;
      return { name, entries };
    })
    .filter(Boolean);
}

function buildGoogleImagesSearchUrl(query) {
  return `https://www.google.com/search?tbm=isch&q=${encodeURIComponent(query)}`;
}

/**
 * Fetches the first Google image result using Programmable Search.
 * This requires REACT_APP_GOOGLE_API_KEY and REACT_APP_GOOGLE_CSE_ID.
 */
async function fetchGoogleImage(query) {
  if (!HAS_GOOGLE_IMAGE_API) return null;

  try {
    const params = new URLSearchParams({
      key: GOOGLE_API_KEY,
      cx: GOOGLE_CSE_ID,
      q: query,
      searchType: 'image',
      num: '1',
      safe: 'active',
    });

    const res = await fetch(`https://www.googleapis.com/customsearch/v1?${params}`);
    if (!res.ok) return null;
    const data = await res.json();

    return data.items?.[0]?.link ?? null;
  } catch {
    return null;
  }
}

/** A single data cell that fetches and toggles its image on click. */
function CharacterCell({ columnName, entry }) {
  // undefined = not yet fetched, null = fetched but no result, string = image URL
  const [image, setImage] = useState(undefined);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const query = `${columnName} ${entry}`;
  const googleImagesUrl = buildGoogleImagesSearchUrl(query);

  const handleClick = async () => {
    const next = !open;
    setOpen(next);
    if (next && image === undefined) {
      setLoading(true);
      const img = await fetchGoogleImage(query);
      setImage(img);
      setLoading(false);
    }
  };

  return (
    <td
      className={`char-cell${open ? ' open' : ''}`}
      onClick={handleClick}
      title={open ? 'Click to collapse' : 'Click to reveal image'}
    >
      <span className="char-name">{entry}</span>
      {open && (
        <div className="char-image">
          {loading ? (
            <div className="loading-text">Loading…</div>
          ) : image ? (
            <img src={image} alt={`${columnName} - ${entry}`} />
          ) : !HAS_GOOGLE_IMAGE_API ? (
            <div className="no-image">
              Add Google API credentials to load inline images.
              <a href={googleImagesUrl} target="_blank" rel="noreferrer">
                Open Google Images
              </a>
            </div>
          ) : (
            <div className="no-image">
              No image found.
              <a href={googleImagesUrl} target="_blank" rel="noreferrer">
                Open Google Images
              </a>
            </div>
          )}
        </div>
      )}
    </td>
  );
}

export default function App() {
  const [columns, setColumns] = useState([]);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('/characters.txt')
      .then(res => {
        if (!res.ok) throw new Error(`Could not load characters.txt (${res.status})`);
        return res.text();
      })
      .then(text => {
        setColumns(parseCharactersTxt(text));
        setLoading(false);
      })
      .catch(e => {
        setError(e.message);
        setLoading(false);
      });
  }, []);

  if (loading) return <div className="status">Loading…</div>;
  if (error)   return <div className="status error">{error}</div>;

  const maxRows = Math.max(...columns.map(c => c.entries.length), 0);

  return (
    <div className="app">
      <h1>Character Gallery</h1>
      <p className="hint">
        Click any character name to reveal a Google Images result.
        {!HAS_GOOGLE_IMAGE_API && ' Set REACT_APP_GOOGLE_API_KEY and REACT_APP_GOOGLE_CSE_ID to load the image inline.'}
      </p>
      <div className="table-wrapper">
        <table>
          <thead>
            <tr>
              {columns.map(col => (
                <th key={col.name}>{col.name}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {Array.from({ length: maxRows }, (_, i) => (
              <tr key={i}>
                {columns.map(col =>
                  col.entries[i] ? (
                    <CharacterCell
                      key={col.name}
                      columnName={col.name}
                      entry={col.entries[i]}
                    />
                  ) : (
                    <td key={col.name} className="empty-cell" />
                  )
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
